stabs = [s.strip() for s in stabilizers_raw.split(',')]
print(f"Number of stabilizers: {len(stabs)}")
print(f"Length of each: {len(stabs[0])}")

# Convert to stim PauliStrings
pauli_stabs = []
for s in stabs:
    pauli_stabs.append(stim.PauliString(s))

print(f"Converted {len(pauli_stabs)} stabilizers")

# Create tableau from stabilizers
try:
    tableau = stim.Tableau.from_stabilizers(pauli_stabs, allow_underconstrained=True)
    print(f"Tableau created with {len(tableau)} qubits")
    
    # Synthesize using graph_state method (CZ-based, cx_count=0)
    circuit = tableau.to_circuit(method='graph_state')
    print(f"Circuit synthesized")
    
    # Count gates
    cx_count = 0
    cz_count = 0
    vol = 0
    for instr in circuit:
        name = instr.name
        if name == 'CX':
            cx_count += len(instr.targets_copy()) // 2
        elif name == 'CZ':
            cz_count += len(instr.targets_copy()) // 2
        if name in ['CX', 'CY', 'CZ', 'H', 'S', 'SQRT_X', 'SQRT_X_DAG', 'SQRT_Y', 'SQRT_Y_DAG', 'S_DAG']:
            if name in ['CX', 'CY', 'CZ']:
                vol += len(instr.targets_copy()) // 2
            else:
                vol += len(instr.targets_copy())
    
    print(f"CX: {cx_count}, CZ: {cz_count}, Volume: {vol}")
    
    # Clean up RX gates (if any) - replace with H for |0> start state
    circuit_str = str(circuit)
    circuit_str = circuit_str.replace('RX ', 'H ')
    
    # Save circuit
    with open(r'C:\Users\anpaz\Repos\quantum-ai\rq3\data\claude-opus-4.6\agent_files\candidate1.stim', 'w') as f:
        f.write(circuit_str)
    print("Saved to candidate1.stim")
    print("\n--- CIRCUIT ---")
    print(circuit_str[:2000])
    
except Exception as e:
    print(f"Error: {e}")
    import traceback
    traceback.print_exc()
